const NFTTracker=require("./services/nftTracker");async function testOpenSeaAPI(){console.log("🧪 Testing OpenSea API integration...\n");const nftTracker=new NFTTracker;await nftTracker.initialize([]);console.log("🔍 Testing OCAS NFT #8430"),console.log("📊 Expected price: ~0.05 ETH\n");try{const openseaPrice=await nftTracker.getOpenSeaNFTPrice("0x078be86f3104a32313a47815792230a3808642cc","8430","Ethereum");console.log(`💰 OpenSea API price: ${openseaPrice} ETH`),openseaPrice>0?console.log(`\n✅ SUCCESS: Found price ${openseaPrice} ETH from OpenSea API!`):console.log("\n❌ FAILED: No price found from OpenSea API")}catch(error){console.error("❌ Test failed:",error.message)}}testOpenSeaAPI().catch(console.error);